SELECT count(*) FROM keyword, movie_keyword, title, movie_info, kind_type, movie_companies, info_type, company_type, cast_info WHERE movie_keyword.keyword_id = keyword.id AND movie_keyword.movie_id = title.id AND movie_info.movie_id = title.id AND title.kind_id = kind_type.id AND movie_companies.movie_id = title.id AND movie_info.info_type_id = info_type.id AND movie_companies.company_type_id = company_type.id AND cast_info.movie_id = title.id;